chart.options:
chart: {
  type: 'bar',
  height: 350,
  stacked: true,
  stackType: '100%'
},
plotOptions: {
  bar: {
    horizontal: true,
  },
},
stroke: {
  width: 1,
  colors: ['#fff']
},
title: {
  text: 'Browser Market Share by Year'
},
xaxis: {
  categories: [2019, 2020, 2021, 2022, 2023, 2024, 2025],
},
tooltip: {
  y: {
    formatter: function (val) {
      return val + "K"
    }
  }
},
fill: {
  opacity: 1

},
legend: {
  position: 'top',
  horizontalAlign: 'left',
  offsetX: 40
}
